/**
 * controllers/analyticsController.js
 * Serves analytics data: KPIs, ABC analysis, forecasts, trends, alerts.
 * Reads from pre-computed JSON (generated by Python engine) with DB fallback.
 */
const path   = require("path");
const fs     = require("fs");
const pool   = require("../config/database");
const logger = require("../utils/logger");

const DATA_PATH = path.resolve(
  process.env.ANALYTICS_DATA_DIR || "../python-analytics/data",
  "analytics_results.json"
);

// Cache analytics in memory, refresh every 10 minutes
let _analyticsCache   = null;
let _cacheTimestamp   = null;
const CACHE_TTL_MS    = 10 * 60 * 1000;

const getAnalytics = () => {
  if (_analyticsCache && Date.now() - _cacheTimestamp < CACHE_TTL_MS) {
    return _analyticsCache;
  }
  try {
    const raw = fs.readFileSync(DATA_PATH, "utf8");
    _analyticsCache  = JSON.parse(raw);
    _cacheTimestamp  = Date.now();
    return _analyticsCache;
  } catch {
    return null;
  }
};

// ── GET /api/analytics/kpis ──────────────────────────────────
const getKpis = async (req, res) => {
  try {
    const analytics = getAnalytics();
    if (analytics?.kpis) {
      return res.json({ success: true, data: analytics.kpis });
    }

    // DB fallback
    const [[kpis]] = await pool.query(`
      SELECT
        ROUND(SUM(s.total_amount), 2)               AS total_revenue_inr,
        ROUND(SUM(p.quantity_in_stock * p.cost_price), 2) AS inventory_value_inr,
        SUM(CASE WHEN p.quantity_in_stock <= p.reorder_level THEN 1 ELSE 0 END) AS low_stock_items,
        COUNT(DISTINCT p.id)                        AS total_products,
        COUNT(DISTINCT s.id)                        AS total_sales_records
      FROM products p
      LEFT JOIN sales s ON s.product_id = p.id
      WHERE p.is_active = 1
    `);

    return res.json({ success: true, data: kpis });
  } catch (err) {
    logger.error(`getKpis: ${err.message}`);
    return res.status(500).json({ success: false, message: "Failed to fetch KPIs" });
  }
};

// ── GET /api/analytics/abc ───────────────────────────────────
const getAbc = async (req, res) => {
  try {
    const analytics = getAnalytics();
    if (analytics?.abc_analysis) {
      return res.json({ success: true, data: analytics.abc_analysis });
    }
    return res.status(503).json({ success: false, message: "Analytics not yet computed" });
  } catch (err) {
    logger.error(`getAbc: ${err.message}`);
    return res.status(500).json({ success: false, message: "Failed to fetch ABC analysis" });
  }
};

// ── GET /api/analytics/trends ────────────────────────────────
const getTrends = async (req, res) => {
  try {
    const { period = "daily" } = req.query;
    const analytics = getAnalytics();

    if (analytics?.sales_trends?.[period]) {
      return res.json({ success: true, data: analytics.sales_trends[period] });
    }

    // DB fallback for daily
    const [rows] = await pool.query(`
      SELECT
        DATE_FORMAT(sale_date, '%Y-%m-%d') AS sale_date,
        ROUND(SUM(total_amount), 2)        AS revenue_inr,
        SUM(quantity_sold)                 AS units_sold
      FROM sales
      WHERE sale_date >= DATE_SUB(CURDATE(), INTERVAL 90 DAY)
      GROUP BY sale_date
      ORDER BY sale_date
    `);

    return res.json({ success: true, data: rows });
  } catch (err) {
    logger.error(`getTrends: ${err.message}`);
    return res.status(500).json({ success: false, message: "Failed to fetch trends" });
  }
};

