// ── GET /api/analytics/category-distribution ─────────────────
const getCategoryDistribution = async (req, res) => {
  try {
    const [rows] = await pool.query(`
      SELECT
        c.id, c.name AS category,
        COUNT(DISTINCT p.id)                            AS product_count,
        ROUND(SUM(s.total_amount), 2)                   AS revenue_inr,
        ROUND(SUM(s.total_amount) / SUM(SUM(s.total_amount)) OVER() * 100, 2) AS revenue_pct
      FROM categories c
      LEFT JOIN products p ON p.category_id = c.id AND p.is_active = 1
      LEFT JOIN sales    s ON s.product_id  = p.id
      GROUP BY c.id, c.name
      ORDER BY revenue_inr DESC
    `);
    return res.json({ success: true, data: rows });
  } catch (err) {
    logger.error(`getCategoryDist: ${err.message}`);
    return res.status(500).json({ success: false, message: "Failed to fetch category data" });
  }
};

