// ── POST /api/analytics/refresh ──────────────────────────────
const refreshAnalytics = async (req, res) => {
  try {
    const { exec } = require("child_process");
    const scriptPath = path.resolve(
      process.env.ANALYTICS_SCRIPT || "../python-analytics/analytics_engine.py"
    );
    const pythonBin = process.env.PYTHON_BIN || "python3";

    exec(`${pythonBin} ${scriptPath}`, (error, stdout, stderr) => {
      if (error) {
        logger.error(`Analytics refresh failed: ${error.message}`);
        return res.status(500).json({ success: false, message: "Analytics refresh failed", error: error.message });
      }
      // Invalidate cache
      _analyticsCache = null;
      _cacheTimestamp = null;
      logger.info("Analytics refreshed via API call");
      return res.json({ success: true, message: "Analytics refreshed successfully", output: stdout });
    });
  } catch (err) {
    logger.error(`refreshAnalytics: ${err.message}`);
    return res.status(500).json({ success: false, message: "Failed to trigger refresh" });
  }
};

module.exports = {
  getKpis, getAbc, getTrends, getDaysOfSupply, getForecasts,
  getRecommendations, getCategoryDistribution, getStockClassification,
  refreshAnalytics,
};
